on_write:
let res = #{ action: "Allow" };
if !payload.contains("valid_from") || !payload.contains("valid_to") {
    res.action = "Reject";
    res.reason = "Temporal data must explicitly state valid_from and valid_to epochs";
}
res

on_read:
let res = #{ payload: payload };
// Read matches if query_key (epoch) falls within the temporal validity window
if payload.valid_from <= query_key && payload.valid_to >= query_key {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
